import { Response } from 'node-fetch';

type FetchType = 'GET' | 'POST' | 'PUT' | 'DELETE';

interface FetchOptions {
  method: FetchType;
  headers?: { [key: string]: string };
  data?: { [key: string]: string };
  responseType?: 'json' | 'text' | 'blob';
  mode?: 'cors' | 'no-cors' | 'same-origin';
}

interface ResponseData {
  status: number;
  statusText: string;
  json(): any;
  text(): string;
  blob(): Blob;
}

async function fetchTypedData(url: string, options: FetchOptions): Promise<ResponseData> {
  try {
    const response = await fetch(url, options);
    const responseType = options.responseType ?? 'json';

    if (response.status >= 200 && response.status < 300) {
      switch (responseType) {
        case 'json':
          return response.json();
        case 'text':
          return response.text();
        case 'blob':
          return response.blob();
        default:
          throw new Error(`Unsupported responseType: ${responseType}`);
      }
    } else {
      throw new Error(`${response.status}: ${response.statusText}`);
    }
  } catch (error) {
    throw error;
  }
}

export default function App(): Promise<void> {
  const response = fetchTypedData('https://example.com/api/data', {
    method: 'GET',
    responseType: 'json'
  });

  response
    .then(data => console.log(data))
    .catch(error => console.error(error));

  return response;
}
